var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SORIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"목적지 도착. 지근거리 안에 포착되는 적 없음. 안전확보완료.","JPN":"目的地到着。至近距離内に捕捉される敵なし。安全確保完了。","ENG":"We have reached the destination. No enemies in sight. Area secured.","TWN":"到達目的地。近距離內沒有發現敵人。確保安全，完畢。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"여긴 옥상이잖아?","JPN":"ここは屋上じゃない？","ENG":"Isn't this the company's rooftop?","TWN":"這裡不是屋頂嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"맞아요. 여긴 금연구역이 되고 직원들의 발길이 뜸해졌으니 안심하셔도 돼요.","JPN":"はい、ここが禁煙区域になってから社員たちもあまり来なくなったので、安心してください。","ENG":"That's right. Don't worry. People stopped coming up here once it was designated a no-smoking area.","TWN":"沒錯。這裡是禁菸區，上來這裡的員工也變少了，大家可以放心。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"네가 날 도와준 거야?","JPN":"あなたが私を助けてくれたの？","ENG":"Were you the one who helped me?","TWN":"是你幫我的嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"전 계획만 세웠을 뿐이에요.","JPN":"僕は計画を立てただけです。","ENG":"I only devised the plan.","TWN":"我只是做做計畫而已。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"계획을 실행에 옮길 수 있었던 건 소림이의 뛰어난 스텔스 능력 덕분이죠.","JPN":"計画を実行できたのはミズキちゃんの優れたステルス能力のおかげです。","ENG":"We couldn't have implemented the plan without Sorim's outstanding stealth abilities.","TWN":"能夠將計劃實際且正確的實施，多虧了蕭林出色的隱身能力。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":" ……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"솔직히 도움을 받을 줄은 몰랐어. 여기 직원들은 전부 사장 말만 따르는 줄 알았거든.","JPN":"正直助けられると思わなかった。ここの社員はみんな社長の指示どおりに動くと思ってたから。","ENG":"Honestly, I didn't expect anyone to help me. I thought all the employees just obeyed the President.","TWN":"說實話，我沒想到會得到幫助。 我以爲這裡的工作人員都只聽老闆的話呢。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":" ……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"직접 보셨다면 알겠지만, 대표님은 지금 몹시 불안정한 상태예요.","JPN":"さっき会ったのでわかると思いますが、社長は今とても不安定な状態なんです。","ENG":"As you may have noticed, the Boss is extremely unstable right now.","TWN":"親眼看到的話就會知道，代表他現在處於非常不穩定的狀態。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"정상은 아니지. 날 회사에 숨어든 스파이라면서 누명을 씌우더니 감옥에 가두려하더라고.","JPN":"まともな状態ではないね。私に会社に忍び込んできたスパイと濡れ衣を着せて、監獄に閉じ込めようとしてたよ。","ENG":"He's definitely not normal. He accused me of being a spy and tried to throw me in jail.","TWN":"根本是非常不正常的情況。 說我是躲在公司的間諜，還冤枉我，又想把我關進監獄。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"그 점은 제가 대신 사과드릴게요!","JPN":"それは僕が代わりに謝罪します！","ENG":"Please let me apologize for that on his behalf!","TWN":"這點我替代表道歉！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"하지만 사실 대표님은 원래 누구보다 밝고 쾌활한 분이었어요.","JPN":"でも本当の社長は元々誰よりも明るくて陽気な方だったんです。","ENG":"You may not believe this, but the Boss used to be more cheery than anyone.","TWN":"但是事實上，代表大人本來是個比任何人都開朗又愉快的人。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"하지만 매출이 급격히 줄어들고 수익이 마이너스가 된 뒤로, 자금난으로 인한 스트레스와 잦은 야근의 피로가 겹치면서 점점 성격이 변하기 시작하셨죠.","JPN":"でも売上が激減して収益がマイナスになってから、資金難によるストレスや残業の疲れが重なり、次第に性格が変わっていったんです。","ENG":"But ever since our sales plummeted and put us in the red, all that stress, compounded with fatigue from working overtime, turned him all strange.","TWN":"但是，在銷售額急劇減少、收益出現負數之後，由於資金困難帶來的壓力和頻繁加班的疲勞，性格開始逐漸發生了扭曲。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"회사가...... 적자라고?","JPN":"会社が……赤字なの？","ENG":"The company... is losing money?","TWN":" 公司…虧損？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"선더볼트단의 규모만 봐도 그렇게 인기가 없는 게임은 아니어 보이던데.","JPN":"サンダーボルト団の規模を見る限り、そんなに人気のないゲームには見えなかったのに。","ENG":"But with all those Thunderbolt fans, I thought the game was pretty popular.","TWN":"單從雷電團的規模來看，也不是那麼不受歡迎的遊戲。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"맞아요! 저희 게임은 수년에 걸쳐 매출 1위를 단 한 번도 놓쳐본 적이 없었어요.","JPN":"そうなんです！　うちのゲームは数年間ずっと売上1位を逃したことはないんですよ。","ENG":"You're right! For years, our game has always been at the top of the charts!","TWN":"沒錯！我們的遊戲在這幾年一次也沒有錯過銷售額第一的位置。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"......적어도 지난 달까지는 그랬죠.","JPN":"……少なくとも先月までは。","ENG":"...Until last month, anyway.","TWN":" ……至少是在前一個月也是如此。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};